import anthropic

client = anthropic.Anthropic()

LABELS = {"billing", "shipping", "technical", "account", "other"}

CLASSIFY_SCHEMA = {
    "type": "object",
    "properties": {
        "intent": {
            "type": "string",
            "enum": sorted(LABELS),
            "description": (
                "billing: payment, invoices, charges, refunds. "
                "shipping: delivery, tracking, lost packages. "
                "technical: app bugs, login issues, API errors. "
                "account: profile, password, subscription settings. "
                "other: anything that does not fit the above."
            ),
        },
        "confidence": {
            "type": "string",
            "enum": ["high", "medium", "low"],
        },
    },
    "required": ["intent", "confidence"],
}

SYSTEM = (
    "You are an intent classifier for a customer support platform. "
    "Classify the user message into exactly one intent label. "
    "When uncertain between two labels, choose the more specific one. "
    "Use 'other' only when no primary label fits."
)


def classify(message: str) -> dict:
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=150,
        system=SYSTEM,
        tools=[{"name": "classify_intent", "input_schema": CLASSIFY_SCHEMA}],
        tool_choice={"type": "tool", "name": "classify_intent"},
        messages=[{"role": "user", "content": message}],
    )
    for block in response.content:
        if block.type == "tool_use":
            result = block.input
            assert result["intent"] in LABELS, f"Invalid label: {result['intent']}"
            return result
    raise RuntimeError("No tool_use block in response")


if __name__ == "__main__":
    cases = [
        "I was charged twice this month",
        "My package hasn't moved in five days",
        "Can't log in — says invalid credentials",
        "I'd like to cancel my plan",
    ]
    for msg in cases:
        out = classify(msg)
        print(f"{msg!r}\n  → intent={out['intent']}, confidence={out['confidence']}\n")

import anthropic, json

client = anthropic.Anthropic()

TOPIC_SCHEMA = {
    "type": "object",
    "properties": {
        "category": {
            "type": "string",
            "enum": ["politics", "technology", "sports", "health", "other"],
        }
    },
    "required": ["category"],
}


def classify_headline(headline: str) -> str:
    resp = client.messages.create(
        model="claude-haiku-4-5",  # fast + cheap for simple classification
        max_tokens=80,
        tools=[{"name": "tag", "input_schema": TOPIC_SCHEMA}],
        tool_choice={"type": "tool", "name": "tag"},
        messages=[{
            "role": "user",
            "content": f"Classify this headline: {headline}",
        }],
    )
    for block in resp.content:
        if block.type == "tool_use":
            return block.input["category"]
    raise RuntimeError("classification failed")


headlines = [
    "Senate passes infrastructure bill",
    "OpenAI releases new reasoning model",
    "World Cup final sets viewing records",
    "Study links sleep deprivation to memory loss",
]
for h in headlines:
    print(f"{classify_headline(h):12s}  {h}")

