import anthropic
from dataclasses import dataclass
from typing import Callable

client = anthropic.Anthropic()

TICKET_SCHEMA = {
    "type": "object",
    "properties": {
        "category": {
            "type": "string",
            "enum": ["billing", "shipping", "technical", "account", "feedback", "other"],
        },
        "severity": {
            "type": "string",
            "enum": ["critical", "high", "medium", "low"],
            "description": "critical=service down or fraud; high=significant impact; medium=degraded; low=minor",
        },
        "sentiment": {
            "type": "string",
            "enum": ["angry", "frustrated", "neutral", "positive"],
        },
        "requires_human": {
            "type": "boolean",
            "description": "true if the issue involves fraud, legal threats, or is too complex for automation",
        },
    },
    "required": ["category", "severity", "sentiment", "requires_human"],
}


@dataclass
class Ticket:
    message: str
    category: str
    severity: str
    sentiment: str
    requires_human: bool


def classify_ticket(message: str) -> Ticket:
    resp = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=200,
        system=(
            "You are a customer support triage system. "
            "Classify tickets accurately. Mark requires_human=true for fraud, "
            "legal threats, account takeovers, or issues needing judgment."
        ),
        tools=[{"name": "triage", "input_schema": TICKET_SCHEMA}],
        tool_choice={"type": "tool", "name": "triage"},
        messages=[{"role": "user", "content": message}],
    )
    for block in resp.content:
        if block.type == "tool_use":
            d = block.input
            return Ticket(
                message=message,
                category=d["category"],
                severity=d["severity"],
                sentiment=d["sentiment"],
                requires_human=d["requires_human"],
            )
    raise RuntimeError("triage failed")


# Routing dispatch table
def handle_billing(t: Ticket) -> str:
    return f"[BILLING BOT] Processing {t.severity} billing issue"

def handle_shipping(t: Ticket) -> str:
    return f"[SHIPPING BOT] Initiating trace for {t.severity} shipment"

def handle_human(t: Ticket) -> str:
    return f"[HUMAN QUEUE] Escalating {t.severity}/{t.sentiment} ticket"

HANDLERS: dict[str, Callable[[Ticket], str]] = {
    "billing": handle_billing,
    "shipping": handle_shipping,
    "technical": lambda t: f"[TECH BOT] Diagnosing {t.severity} issue",
    "account":   lambda t: f"[ACCOUNT BOT] Handling {t.category}",
    "other":     lambda t: f"[GENERAL BOT] Routing to general queue",
    "feedback":  lambda t: f"[FEEDBACK BOT] Logging {t.sentiment} feedback",
}


def route(message: str) -> str:
    ticket = classify_ticket(message)
    print(f"  category={ticket.category}, severity={ticket.severity}, "
          f"sentiment={ticket.sentiment}, human={ticket.requires_human}")
    if ticket.requires_human or ticket.severity == "critical":
        return handle_human(ticket)
    return HANDLERS.get(ticket.category, HANDLERS["other"])(ticket)


if __name__ == "__main__":
    messages = [
        "I was charged $500 I did not authorize — I'm reporting fraud!",
        "My order says delivered but nothing arrived",
        "The export button doesn't work on Firefox",
    ]
    for msg in messages:
        print(f"\nInput: {msg!r}")
        print(f"Result: {route(msg)}")

import anthropic
import json
from dataclasses import dataclass, asdict
from typing import Optional
import logging

logger = logging.getLogger("triage")
client = anthropic.Anthropic()

MODERATION_SCHEMA = {
    "type": "object",
    "properties": {
        "action": {
            "type": "string",
            "enum": ["allow", "flag", "block"],
            "description": (
                "allow: clearly safe content. "
                "flag: borderline, needs human review. "
                "block: clear policy violation."
            ),
        },
        "violation_type": {
            "type": "string",
            "enum": ["none", "spam", "harassment", "misinformation", "adult", "violence", "other_violation"],
        },
        "confidence": {"type": "string", "enum": ["high", "medium", "low"]},
        "reason": {
            "type": "string",
            "description": "One-sentence explanation — required when action is not allow.",
        },
    },
    "required": ["action", "violation_type", "confidence"],
}


@dataclass
class ModerationDecision:
    action: str
    violation_type: str
    confidence: str
    reason: Optional[str] = None
    error: Optional[str] = None


def moderate(text: str, post_id: str) -> ModerationDecision:
    try:
        resp = client.messages.create(
            model="claude-haiku-4-5",
            max_tokens=150,
            system=(
                "You are a content moderator. Classify content accurately and conservatively. "
                "Prefer 'flag' over 'block' when uncertain. "
                "Only 'block' content that clearly violates policy."
            ),
            tools=[{"name": "moderate", "input_schema": MODERATION_SCHEMA}],
            tool_choice={"type": "tool", "name": "moderate"},
            messages=[{"role": "user", "content": f"Moderate this post:\n\n{text}"}],
        )
        for block in resp.content:
            if block.type == "tool_use":
                d = block.input
                decision = ModerationDecision(**{k: d.get(k) for k in ModerationDecision.__dataclass_fields__})
                logger.info("moderation post_id=%s decision=%s", post_id, asdict(decision))
                return decision
    except Exception as exc:
        logger.error("moderation error post_id=%s err=%s", post_id, exc)
        # Fail-safe: flag on error rather than allow
        return ModerationDecision(action="flag", violation_type="none",
                                   confidence="low", error=str(exc))
    return ModerationDecision(action="flag", violation_type="none", confidence="low")
